head.script:
//-------------------------------------------------------------------------
// 전역변수
//-------------------------------------------------------------------------
scwin.firstDate = WebSquare.date.getCurrentServerDate();  // 서버를 기준으로 현재 날짜 반환
scwin.loginDTO = $c.data.getMemInfo();
scwin.loUpperLobranCd = $c.data.getMemInfo("loUpperLobranCd");


//-------------------------------------------------------------------------
// 화면로딩시
//-------------------------------------------------------------------------
scwin.onpageload = function() {

    scwin.f_setHeaderInspection();
};


//-------------------------------------------------------------------------
// Default Data Setting
//-------------------------------------------------------------------------
scwin.f_setHeaderInspection = function() { 
    ica_wrkStYmDd.setValue(scwin.firstDate);

}


//-------------------------------------------------------------------------
// UDC 공통 팝업 (작업장)
//-------------------------------------------------------------------------
scwin.udc_wrkPl_onClick = async function (e) {
    let lodeptCd = acb_branCd.getValue();
    let paramList = ","+lodeptCd+"";

    udc_wrkPl.cfCommonPopUp(scwin.udc_wrkPl_callBackFunc
    , ed_wrkPlCd.getValue()
    ,ed_wrkPlNm.getValue()
    ,"F"
    ,null
    ,null
    ,null
    ,null
    ,',' + acb_branCd.getValue() + ''
    ,null
    ,null
    ,null
    ,null
    ,null
    ,null
    );

};

scwin.udc_wrkPl_onblurCode = async function (e) {
    let lodeptCd = acb_branCd.getValue();
    let paramList = ","+lodeptCd+"";
    if(ed_wrkPlCd.getValue() != "") {
        udc_wrkPl.cfCommonPopUp(scwin.udc_wrkPl_callBackFunc
        , ed_wrkPlCd.getValue()
         ,""
         ,"T"
        ,null
        ,null
        ,null
        ,null
        ,',' + acb_branCd.getValue() + ''
        ,null
        ,null
        ,null
        ,null
        ,null
        ,null
        );
    }else {
        return;
    }
};

scwin.udc_wrkPl_onChangeName = async function (info) {
    let lodeptCd = acb_branCd.getValue();
    let paramList = ","+lodeptCd+"";
    if(ed_wrkPlNm.getValue() != "") {
        udc_wrkPl.cfCommonPopUp(scwin.udc_wrkPl_callBackFunc
        , ""
        ,ed_wrkPlNm.getValue()
        ,"T"
        ,null
        ,null
        ,null
        ,null
        ,',' + acb_branCd.getValue() + ''
        ,null
        ,null
        ,null
        ,null
        ,null
        ,null
        );
    } else {
        return;
    }
};


//-------------------------------------------------------------------------
// UDC 공통 팝업 콜백 (작업장)
//-------------------------------------------------------------------------
scwin.udc_wrkPl_callBackFunc = function(ret) {
    $c.gus.cfSetReturnValue(ret, ed_wrkPlCd, ed_wrkPlNm);
};

//-------------------------------------------------------------------------
// 검색영역 Field Clear함.
//-------------------------------------------------------------------------
scwin.btn_init_onClick = function (e) {
    $c.gus.cfInitObjects(tb_mainData);
    acb_branCd.focus();
};


//-------------------------------------------------------------------------
// 출력 f_OzReport
//-------------------------------------------------------------------------
scwin.btn_OzReport_onClick = async function (e) {

    var fileName = "";

    if (! await $c.gus.cfValidate([tb_mainData])) {
    	return;
    }

    if( acb_div.getValue() == "0085" ) { //퇴직충당금
    	fileName = "/ds/op/wrkrslts/wagewrkrslts/op_307_01_07.ozr";
    } else if( acb_div.getValue() == "0218") { //교육훈련비
    	fileName = "/ds/op/wrkrslts/wagewrkrslts/op_307_01_09.ozr";
    } else if( acb_div.getValue() == "0072") { //현대화기금
    	fileName = "/ds/op/wrkrslts/wagewrkrslts/op_307_01_11.ozr";
    } else {
    	return;
    }

    scwin.f_OzReport(fileName);
};


//-------------------------------------------------------------------------
// 출력 f_OzReport
//-------------------------------------------------------------------------
scwin.f_OzReport = function(str) {

    let tocChk = "";

    if(cbx_toc.getValue() == "1") {
        tocChk = "1";
    } else {
        tocChk = "0";
    }


    let data = {
        odiName : "op_307_01_07",
        reportName: "",
        odiParam : {
            dt: ica_wrkStYmDd.getValue(),
            wrkPl: ed_wrkPlCd.getValue(),
            dept : acb_branCd.getValue(),
            div : acb_div.getValue(),
            cntrBulk : acb_cb.getValue(),
            toc : tocChk
        },
        viewerParam : {
            useprogressbar : false, // 프로그레스바 쓸지 말지
            printcommand : true,
            zoom : 90, // 배율 설정
        },
        formParam: {
            mode : "preview"
        }
    };

    data.reportName = str;

    scwin.openPopup(data);

}


scwin.openPopup = async function(data){
    let opts = {
        id: "ozReportPopup",
        popupName: "오즈 리포트",
        modal: true,
        type: "browserPopup",
        width: 1000,
        height: 600,
        title: "오즈 리포트"
    };
    await $c.win.openPopup("/ui/cm/zz/ozreportPopup.xml", opts, data);
}
